import{_ as e,o as a,c as s,ag as i}from"./chunks/framework.DmiPl2jb.js";const u=JSON.parse('{"title":"CSP compatibility","description":"","frontmatter":{},"headers":[],"relativePath":"cookbook/csp-compatibility.md","filePath":"cookbook/csp-compatibility.md"}'),o={name:"cookbook/csp-compatibility.md"};function n(d,t,r,l,c,h){return a(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="csp-compatibility" tabindex="-1">CSP compatibility <a class="header-anchor" href="#csp-compatibility" aria-label="Permalink to &quot;CSP compatibility&quot;">​</a></h1><p>a11y-hud is a dev tool — it typically runs in environments where CSP is either absent or loosely configured. This guide covers what you need if your development or staging environment enforces a CSP.</p><h2 id="what-a11y-hud-loads" tabindex="-1">What a11y-hud loads <a class="header-anchor" href="#what-a11y-hud-loads" aria-label="Permalink to &quot;What a11y-hud loads&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Source</th><th>When</th><th>Description</th></tr></thead><tbody><tr><td><code>https://cdn.jsdelivr.net/npm/a11y-hud/…</code></td><td>Bookmarklet, CDN script tag</td><td>UMD bundle loaded from jsDelivr</td></tr><tr><td><code>https://cdn.jsdelivr.net/npm/axe-core/…</code></td><td>(Bundled — no separate load)</td><td>axe-core is bundled into <code>a11y-hud</code></td></tr><tr><td>Inline styles</td><td>Always</td><td>HUD styles via Constructable Stylesheets inside Shadow DOM</td></tr></tbody></table><h2 id="npm-bundler-path-no-cdn" tabindex="-1">npm + bundler path (no CDN) <a class="header-anchor" href="#npm-bundler-path-no-cdn" aria-label="Permalink to &quot;npm + bundler path (no CDN)&quot;">​</a></h2><p>When you import from npm (<code>import { mount } from &quot;a11y-hud&quot;</code>), nothing is loaded from a CDN at runtime. The bundle is served by your own dev server. <strong>No external <code>script-src</code> or <code>connect-src</code> directives are needed.</strong></p><p>The HUD applies styles using Constructable Stylesheets (<code>document.adoptedStyleSheets</code>), which are internal to the Shadow Root. No <code>&lt;link&gt;</code> tags, no external stylesheet requests.</p><p>The only CSP consideration for the npm path:</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Content-Security-Policy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> style-src &#39;unsafe-inline&#39;;</span></span></code></pre></div><p>This is needed because <code>CSSStyleSheet</code> with <code>replaceSync()</code> is classified as an inline style by some browsers. The fallback path (older Safari) uses a <code>&lt;style&gt;</code> element inside Shadow DOM, which also requires <code>&#39;unsafe-inline&#39;</code>.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><code>&#39;unsafe-inline&#39;</code> only covers inline styles, not inline scripts. It does not weaken your <code>script-src</code> directive.</p></div><h2 id="cdn-script-tag-path" tabindex="-1">CDN script tag path <a class="header-anchor" href="#cdn-script-tag-path" aria-label="Permalink to &quot;CDN script tag path&quot;">​</a></h2><p>If you&#39;re loading a11y-hud from jsDelivr:</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Content-Security-Policy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  script-src &#39;self&#39; https://cdn.jsdelivr.net;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  style-src &#39;self&#39; &#39;unsafe-inline&#39;;</span></span></code></pre></div><h2 id="bookmarklet-path" tabindex="-1">Bookmarklet path <a class="header-anchor" href="#bookmarklet-path" aria-label="Permalink to &quot;Bookmarklet path&quot;">​</a></h2><p>The bookmarklet injects a <code>&lt;script&gt;</code> tag pointing to jsDelivr. This requires:</p><div class="language-http vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">http</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">Content-Security-Policy</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  script-src &#39;self&#39; https://cdn.jsdelivr.net;</span></span></code></pre></div><p>On staging environments with a strict CSP that blocks CDN scripts, the bookmarklet will fail silently (the injected <code>&lt;script&gt;</code> is blocked). The fix is to either:</p><ol><li><strong>Temporarily relax the CSP</strong> for the staging environment only (common practice — staging is not production).</li><li><strong>Use the npm path</strong> instead of the bookmarklet — self-host the bundle and update your bookmarklet URL to point to it.</li><li><strong>Create a custom bookmarklet</strong> that points to a self-hosted copy of the UMD bundle.</li></ol><h2 id="axe-core-and-iframe-inspection" tabindex="-1">axe-core and iframe inspection <a class="header-anchor" href="#axe-core-and-iframe-inspection" aria-label="Permalink to &quot;axe-core and iframe inspection&quot;">​</a></h2><p>axe-core can inspect <code>&lt;iframe&gt;</code> contents if the frame is same-origin. Cross-origin iframes are skipped automatically. This is a browser security constraint unrelated to CSP.</p><h2 id="summary-table" tabindex="-1">Summary table <a class="header-anchor" href="#summary-table" aria-label="Permalink to &quot;Summary table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Path</th><th><code>script-src</code></th><th><code>style-src</code></th><th>Notes</th></tr></thead><tbody><tr><td>npm + bundler</td><td>Not needed</td><td><code>&#39;unsafe-inline&#39;</code></td><td>Dev server serves the bundle</td></tr><tr><td>CDN <code>&lt;script&gt;</code> tag</td><td><code>https://cdn.jsdelivr.net</code></td><td><code>&#39;unsafe-inline&#39;</code></td><td></td></tr><tr><td>Bookmarklet</td><td><code>https://cdn.jsdelivr.net</code></td><td><code>&#39;unsafe-inline&#39;</code></td><td>May be blocked on strict staging CSP</td></tr></tbody></table>`,23)])])}const m=e(o,[["render",n]]);export{u as __pageData,m as default};
